#include <stdio.h>
#include <stdint.h>
#define MAX_PI 100000
int64_t factorial[MAX_PI + 1];

void precompute_factorials() {
    factorial[0] = 1;
    for (int i = 1; i <= MAX_PI; i++) {
        factorial[i] = (factorial[i - 1] * i) % 1000000007;
    }
}

int64_t calculate_F(int64_t x) {
    int64_t result = 0;
    for (int i = 1; i <= x; i++) {
        result = (result + i * (factorial[i] + x)) % 1000000007;
    }
    return result;
}

int main() {
    precompute_factorials();
    int n, m;
    scanf("%d %d", &n, &m);
    int64_t sum = 0;
    for (int i = 0; i < n; i++) {
        int64_t pi;
        scanf("%lld", &pi);
        sum = (sum + calculate_F(pi)) % m;
    }
    printf("%lld\n", sum);
    return 0;
}

