import java.util.Scanner;
public class Main {
    public static long[] factorial;
    public static void precompute_factorials(int max_pi) {
        factorial = new long[max_pi + 1];
        factorial[0] = 1;
        for (int i = 1; i <= max_pi; i++) {
            factorial[i] = (factorial[i - 1] * i) % 1000000007;
        }
    }

    public static long calculate_F(long x) {
        long result = 0;
        for (int i = 1; i <= x; i++) {
            result = (result + i * (factorial[i] + x)) % 1000000007;
        }
        return result;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int m = scanner.nextInt();
        precompute_factorials(100000);
        long sum = 0;
        for (int i = 0; i < n; i++) {
            long pi = scanner.nextLong();
            sum = (sum + calculate_F(pi)) % m;
        }
        System.out.println(sum);
    }
}

